UserObject.plantUmlData:
{
  "data": "@startuml
title Swimlane Activity Diagram - HealPay (AI-Based Medical Billing Automation System)

|Patient|
start
:Visit Clinic;
:Provide personal and insurance information;

|Doctor|
:Examine patient;
:Enter diagnosis and treatment details into system;

|System|
:Store patient and consultation details;
:Check if documents need OCR processing;

if (Scanned documents available?) then (Yes)
  :Perform OCR to extract text data;
else (No)
  :Proceed without OCR;
endif

|Medical Coder|
:Review diagnosis;
:Assign ICD & CPT codes;

|System|
:Validate medical codes;
:Save coded medical record in database;

|Insurance Provider|
if (Patient has insurance?) then (Yes)
  |System|
  :Send insurance eligibility request;
  |Insurance Provider|
  :Verify policy & coverage;
  :Return claim approval/rejection;
else (No)
  |System|
  :Proceed with self-pay process;
endif

|Billing Staff|
if (Claim approved?) then (Yes)
  :Generate insurance-based invoice;
else (No)
  :Generate self-pay invoice;
endif

|System|
:Run AI-based anomaly/fraud detection;

if (Anomaly detected?) then (Yes)
  |Admin|
  :Review flagged invoice;
  :Approve or reject after validation;
else (No)
  |System|
  :Mark invoice as clean;
endif

|Patient|
:Receive invoice notification;
:Make payment (Cash/Card/Online);

|System|
:Update payment status;
:Generate payment receipt;

stop
@enduml
",
  "format": "svg"
}
